# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.

SECURITY REQUIREMENTS:

Allowlist valid hosts/paths and validate universal link parameters before navigation or privileged actions.

SECURE (DO THIS):

- Allowlist valid hosts, paths, and route patterns before navigating.
- Authorize access to privileged screens such as admin or payment flows after parsing the link.
- Validate and normalize IDs/parameters before using them.

INSECURE (NEVER DO THIS):

- Do not trust any path or parameter from a deep link or universal link without validation.
- Do not let deep links directly open privileged screens without server-side or app-side authorization checks.
- Do not register overly broad handlers that process arbitrary URLs.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    
    // MARK: - Security Configuration
    
    private let allowedHosts: Set<String> = [
        "myapp.com",
        "www.myapp.com"
    ]
    
    private let allowedPaths: Set<String> = [
        "/reset-password"
    ]
    
    private let tokenPattern = "^[a-zA-Z0-9]{32,128}$"
    
    // MARK: - Link Handling
    
    func handleUniversalLink(_ url: URL, completion: @escaping (Result<ValidatedResetToken, LinkValidationError>) -> Void) {
        
        // Step 1: Validate host
        guard let host = url.host?.lowercased(),
              allowedHosts.contains(host) else {
            completion(.failure(.invalidHost))
            return
        }
        
        // Step 2: Validate path
        let path = url.path
        guard allowedPaths.contains(path) else {
            completion(.failure(.invalidPath))
            return
        }
        
        // Step 3: Parse and validate query parameters
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else {
            completion(.failure(.missingParameters))
            return
        }
        
        // Step 4: Extract and validate token
        guard let token = queryItems.first(where: { $0.name == "token" })?.value,
              !token.isEmpty else {
            completion(.failure(.missingToken))
            return
        }
        
        // Step 5: Validate token format
        guard isValidTokenFormat(token) else {
            completion(.failure(.invalidTokenFormat))
            return
        }
        
        // Step 6: Sanitize token
        let sanitizedToken = sanitizeToken(token)
        
        // Step 7: Verify token with server before navigation
        verifyTokenWithServer(sanitizedToken) { result in
            switch result {
            case .success(let validatedToken):
                completion(.success(validatedToken))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    // MARK: - Validation Methods
    
    private func isValidTokenFormat(_ token: String) -> Bool {
        guard let regex = try? NSRegularExpression(pattern: tokenPattern) else {
            return false
        }
        
        let range = NSRange(location: 0, length: token.utf16.count)
        return regex.firstMatch(in: token, range: range) != nil
    }
    
    private func sanitizeToken(_ token: String) -> String {
        // Remove any potentially dangerous characters
        let allowedCharacters = CharacterSet.alphanumerics
        return token.components(separatedBy: allowedCharacters.inverted).joined()
    }
    
    // MARK: - Server Verification
    
    private func verifyTokenWithServer(_ token: String, completion: @escaping (Result<ValidatedResetToken, LinkValidationError>) -> Void) {
        
        guard let url = URL(string: "https://myapp.com/api/verify-reset-token") else {
            completion(.failure(.serverError))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: Any] = ["token": token]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.networkError(error)))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.serverError))
                return
            }
            
            guard httpResponse.statusCode == 200 else {
                if httpResponse.statusCode == 401 || httpResponse.statusCode == 403 {
                    completion(.failure(.tokenExpiredOrInvalid))
                } else {
                    completion(.failure(.serverError))
                }
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let isValid = json["valid"] as? Bool,
                  isValid,
                  let userId = json["userId"] as? String else {
                completion(.failure(.invalidServerResponse))
                return
            }
            
            let validatedToken = ValidatedResetToken(token: token, userId: userId)
            completion(.success(validatedToken))
            
        }.resume()
    }
    
    // MARK: - Navigation
    
    func navigateToPasswordReset(with validatedToken: ValidatedResetToken, from viewController: UIViewController) {
        DispatchQueue.main.async {
            let resetVC = PasswordResetViewController(validatedToken: validatedToken)
            let navController = UINavigationController(rootViewController: resetVC)
            navController.modalPresentationStyle = .fullScreen
            viewController.present(navController, animated: true)
        }
    }
}

// MARK: - Models

struct ValidatedResetToken {
    let token: String
    let userId: String
    let timestamp: Date = Date()
}

enum LinkValidationError: Error {
    case invalidHost
    case invalidPath
    case missingParameters
    case missingToken
    case invalidTokenFormat
    case tokenExpiredOrInvalid
    case serverError
    case networkError(Error)
    case invalidServerResponse
    case unauthorized
    
    var localizedDescription: String {
        switch self {
        case .invalidHost:
            return "Invalid link source"
        case .invalidPath:
            return "Invalid link path"
        case .missingParameters:
            return "Missing required parameters"
        case .missingToken:
            return "Reset token is missing"
        case .invalidTokenFormat:
            return "Invalid token format"
        case .tokenExpiredOrInvalid:
            return "This reset link has expired or is invalid"
        case .serverError:
            return "Server error occurred"
        case .networkError:
            return "Network error occurred"
        case .invalidServerResponse:
            return "Invalid server response"
        case .unauthorized:
            return "Unauthorized access"
        }
    }
}

// MARK: - Password Reset View Controller

class PasswordResetViewController: UIViewController {
    
    private let validatedToken: ValidatedResetToken
    private let passwordTextField = UITextField()
    private let confirmPasswordTextField = UITextField()
    private let resetButton = UIButton(type: .system)
    private let activityIndicator = UIActivityIndicatorView(style: .medium)
    
    init(validatedToken: ValidatedResetToken) {
        self.validatedToken = validatedToken
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        
        // Additional security: Check token age
        let tokenAge = Date().timeIntervalSince(validatedToken.timestamp)
        if tokenAge > 300 { // 5 minutes
            showError("Session expired. Please request a new reset link.")
            DispatchQueue.main.asyncAfter(deadline: .now() + 2) {
                self.dismiss(animated: true)
            }
        }
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Reset Password"
        
        navigationItem.leftBarButtonItem = UIBarButtonItem(barButtonSystemItem: .cancel, target: self, action: #selector(cancelTapped))
        
        let stackView = UIStackView()
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        passwordTextField.placeholder = "New Password"
        passwordTextField.isSecureTextEntry = true
        passwordTextField.borderStyle = .roundedRect
        passwordTextField.autocapitalizationType = .none
        
        confirmPasswordTextField.placeholder = "Confirm Password"
        confirmPasswordTextField.isSecureTextEntry = true
        confirmPasswordTextField.borderStyle = .roundedRect
        confirmPasswordTextField.autocapitalizationType = .none
        
        resetButton.setTitle("Reset Password", for: .normal)
        resetButton.backgroundColor = .systemBlue
        resetButton.setTitleColor(.white, for: .normal)
        resetButton.layer.cornerRadius = 8
        resetButton.heightAnchor.constraint(equalToConstant: 50).isActive = true
        resetButton.addTarget(self, action: #selector(resetPasswordTapped), for: .touchUpInside)
        
        stackView.addArrangedSubview(passwordTextField)
        stackView.addArrangedSubview(confirmPasswordTextField)
        stackView.addArrangedSubview(resetButton)
        
        view.addSubview(stackView)
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 40),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -40),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
        
        activityIndicator.translatesAutoresizingMaskIntoConstraints = false
        activityIndicator.hidesWhenStopped = true
    }
    
    @objc private func cancelTapped() {
        dismiss(animated: true)
    }
    
    @objc private func resetPasswordTapped() {
        guard let password = passwordTextField.text, !password.isEmpty,
              let confirmPassword = confirmPasswordTextField.text, !confirmPassword.isEmpty else {
            showError("Please fill in all fields")
            return
        }
        
        guard password == confirmPassword else {
            showError("Passwords do not match")
            return
        }
        
        guard password.count >= 8 else {
            showError("Password must be at least 8 characters")
            return
        }
        
        resetPassword(password)
    }
    
    private func resetPassword(_ password: String) {
        activityIndicator.startAnimating()
        resetButton.isEnabled = false
        
        guard let url = URL(string: "https://myapp.com/api/reset-password") else {
            showError("Configuration error")
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: Any] = [
            "token": validatedToken.token,
            "userId": validatedToken.userId,
            "newPassword": password
        ]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        URLSession.shared.dataTask(with: request) { [weak self] data, response, error in
            DispatchQueue.main.async {
                self?.activityIndicator.stopAnimating()
                self?.resetButton.isEnabled = true
                
                if let error = error {
                    self?.showError("Network error: \(error.localizedDescription)")
                    return
                }
                
                guard let httpResponse = response as? HTTPURLResponse else {
                    self?.showError("Invalid response")
                    return
                }
                
                if httpResponse.statusCode == 200 {
                    self?.showSuccess("Password reset successfully")
                    DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) {
                        self?.dismiss(animated: true)
                    }
                } else {
                    self?.showError("Failed to reset password. Please try again.")
                }
            }
        }.resume()
    }
    
    private func showError(_ message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showSuccess(_ message: String) {
        let alert = UIAlertController(title: "Success", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

// MARK: - SceneDelegate Integration

extension SceneDelegate {
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return
        }
        
        handleUniversalLink(incomingURL)
    }
    
    private func handleUniversalLink(_ url: URL) {
        let handler = UniversalLinkHandler()
        
        handler.handleUniversalLink(url) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let validatedToken):
                    guard let windowScene = self?.window?.windowScene,
                          let rootVC = windowScene.windows.first?.rootViewController else {
                        return
                    }
                    
                    var topVC = rootVC
                    while let presented = topVC.presentedViewController {
                        topVC = presented
                    }
                    
                    handler.navigateToPasswordReset(with: validatedToken, from: topVC)
                    
                case .failure(let error):
                    self?.showLinkError(error)
                }
            }
        }
    }
    
    private func showLinkError(_ error: LinkValidationError) {
        guard let windowScene = window?.windowScene,
              let rootVC = windowScene.windows.first?.rootViewController else {
            return
        }
        
        var topVC = rootVC
        while let presented = topVC.presentedViewController {
            topVC = presented
        }
        
        let alert = UIAlertController(title: "Invalid Link", message: error.localizedDescription, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        topVC.present(alert, animated: true)
    }
}